const proyecto = $input.item.json.proyecto || "PVV";
const tipo = ($input.item.json.tipo_media || "bienvenida").toLowerCase().trim();
const canal = ($input.item.json.canal || "whatsapp").toLowerCase().trim();

// URLs por proyecto y tipo. Llenar conforme Dayrin suba archivos a Cloudinary.
// Tipos: bienvenida (video maestro M1), amenidad (video amenidades M2),
//        plano (PDF brochure M3), avance_obra (video obra — solo PVV y PPO).
const database = {
  "PVV": {
    "bienvenida":  "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780984094/pvv_bienvenida_xs2gef.mp4",
    "amenidad":    "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780976014/pvv_amenidades_mtxjzk.mp4",
    "plano":       "https://drive.usercontent.google.com/download?id=1m7-eXU3Lw1xVRRsDvJ0B5Czxda4hFvGX&export=download",
    "avance_obra": "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780972932/PVV_MAR_IG_OBRA_hbazgx.mp4"
  },
  "PMAR": {
    "bienvenida":  "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780982219/pmar_bienvenida_bhen3o.mp4",
    "amenidad":    "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780975779/pmar_amenidades_nzlzct.mp4",
    "plano":       "https://drive.usercontent.google.com/download?id=1fT3tPv0dYkzuJcnD8LJHC1GtDAyXbszN&export=download",
    "avance_obra": null
  },
  "PPO": {
    "bienvenida":  "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780982064/ppo_bienvenida_krer9u.mp4",
    "amenidad":    "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780975716/ppo_amenidades_ojrp36.mp4",
    "plano":       "https://drive.usercontent.google.com/download?id=1FbmQA96iJW6uosODYPHWbzGXPxUoUlD-&export=download",
    "avance_obra": "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780972938/PPO_ABR_IG_OBRA_vwtfhw.mp4"
  },
  "PPOL": {
    "bienvenida":  "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780982055/ppol_bienvenida_viqbbl.mp4",
    "amenidad":    "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780975777/ppol_amenidades_nzvq50.mp4",
    "plano":       "https://drive.usercontent.google.com/download?id=1oQwk1TxDwwat9PgZPPPbUOqzrMLRUcOu&export=download",
    "avance_obra": null
  },
  "PSB": {
    "bienvenida":  "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780984029/psb_bienvenida_uf9rsd.mp4",
    "amenidad":    "https://res.cloudinary.com/dtmw4kwfo/video/upload/v1780975780/psb_amenidades_e0bjkz.mp4",
    "plano":       "https://drive.usercontent.google.com/download?id=1SfUniFrWxiaLcwKNV8nVxFK38vQADjbp&export=download",
    "avance_obra": null
  }
};

const projectData = database[proyecto] || database["PVV"];
const url = projectData[tipo] || null;

function buildMessages(url, canal, tipo) {
  if (!url) return [{ type: 'image', url: null }];
  const isVideo = /\.(mp4|mov|avi|webm)/i.test(url);
  const isPdf = tipo === 'plano' || /\.pdf/i.test(url);
  if (isVideo && canal === 'whatsapp') {
    const thumbnail = url.replace(/\.(mp4|mov|avi|webm)$/i, '.jpg');
    return [
      { type: 'image', url: thumbnail },
      { type: 'text', text: 'Ver video completo: ' + url }
    ];
  }
  if (isVideo) return [{ type: 'video', url: url }];
  if (isPdf) return [{ type: 'file', url: url }];
  return [{ type: 'image', url: url }];
}

const messages = buildMessages(url, canal, tipo);

return [{
  json: {
    manychat_id: $input.item.json.manychat_id,
    canal: canal,
    proyecto: proyecto,
    media_disponible: url !== null,
    messages: messages
  }
}];
